VALUES
  ('bookkeeper-moex-01029', 'bookkeeper', 'bookkeeper-moex-106-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '李中華分別於106年2月1日、3月1日及4月1日將財產贈與子女，歷次金額依序為$2,000,000、$3,000,000 及$4,000,000。請問李君106年度首次申報贈與稅之期限及贈與淨額分別為何？ 106年2月2日起30日內申報，贈與淨額$2,000,000 106年3月2日起30日內申報，贈與淨額$2,800,000 106年3月2日起30日內申報，贈與淨額$3,000,000 106年4月2日起30日內申報，贈與淨額$4,000,000', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:25+00:00", "source_pdf_sha1": "94033dba30f4", "answer_pdf_sha1": "57df1534c299", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "602", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 47, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01030', 'bookkeeper', 'bookkeeper-moex-106-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '遺產稅納稅義務人以實物抵繳遺產稅時，下列敘述何者正確？ 由繼承人逾三分之一同意提出申請 由繼承人過半數同意提出申請 由繼承人之應繼分合計過半數之同意提出申請 由繼承人之應繼分合計逾三分之二之同意提出申請', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:25+00:00", "source_pdf_sha1": "94033dba30f4", "answer_pdf_sha1": "57df1534c299", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "602", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 48, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01031', 'bookkeeper', 'bookkeeper-moex-106-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依現行遺產及贈與稅法之規定，下列那些行為須課徵贈與稅？ 扶養義務人為受扶養人支付之生活費、教育費及醫藥費 保證人因履行保證責任，而代主債務人清償債務，並無償免除其債務者 先生贈與太太之財產 捐贈公益慈善機關之財產', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:25+00:00", "source_pdf_sha1": "94033dba30f4", "answer_pdf_sha1": "57df1534c299", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "602", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 49, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01032', 'bookkeeper', 'bookkeeper-moex-106-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依現行遺產及贈與稅法規定，下列何項應計入遺產課稅？ 被繼承人收藏之藝術品   被繼承人之發明專利權 被繼承人死亡前5年內贈與其配偶之財產   被繼承人生前教學用之鋼琴，價值$300,000', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:25+00:00", "source_pdf_sha1": "94033dba30f4", "answer_pdf_sha1": "57df1534c299", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "602", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 50, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01033', 'bookkeeper', 'bookkeeper-moex-106-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '依現行記帳士法之規定，某君未依法取得記帳士或記帳及報稅代理業務人資格，擅自代他人記帳及報稅 者，應如何處置？ 由法院處一年以下有期徒刑、拘役或科或併科新臺幣15萬元以下罰鍰 由經濟部處新臺幣10萬元以下罰金 由財政部處新臺幣3萬元以上15萬元以下罰鍰 由稅捐機關處新臺幣1萬元以上5萬元以下罰金', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "c473f73014d0", "answer_pdf_sha1": "8e580acee728", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "602", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 1, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01034', 'bookkeeper', 'bookkeeper-moex-106-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '彰化公司與陳記帳士簽訂委任書，委託其向國稅局報繳本期營業稅，因陳記帳士的疏忽漏報一筆巨額銷', '["國稅局罰鍰對象為彰化公 司", "國稅局罰鍰對象為陳記帳士", "陳記帳士可以不負賠償責任", "陳記帳士應負賠償責任 ⑤陳記帳士 此項行為屬應付懲戒事項"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "c473f73014d0", "answer_pdf_sha1": "8e580acee728", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "602", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01035', 'bookkeeper', 'bookkeeper-moex-106-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '王台中係記帳及報稅代理人，其每年皆參加專業訓練單位舉辧之專業訓練課程，其考評狀況：民國 104 年以前（含104年）每年皆合格、105年不合格，106年合格，其105年、106年及107年可否執業情況， 下列敍述何者正確？ 年不能執業、106年可執業、107年可執業 年可執業、106年不能執業、107年可執業 年可執業、106年不能執業、107年須視107年考評狀況 年可執業、106年不能執業、107年不能執業', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "c473f73014d0", "answer_pdf_sha1": "8e580acee728", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "602", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 3, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01036', 'bookkeeper', 'bookkeeper-moex-106-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '李大同105年11月記帳士考試及格，準備在臺北市大同區設立事務所執業，請問與其有關之相關機關，下', '["記帳士證書由考選部核發", "登錄執業機關為臺北國稅局", "記帳士主管機關為臺北市政 府", "稅務部分業務事件主管機關為財政部 ⑤商業會計業務事件主管機關為經濟部 ⑥商業登記業務事件 主管機關為財政部 ⑦記帳士懲戒委員會處理懲戒事件，認為有犯罪嫌疑者，由記帳士懲戒委員會偵辦"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "c473f73014d0", "answer_pdf_sha1": "8e580acee728", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "602", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01037', 'bookkeeper', 'bookkeeper-moex-106-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '李記帳士受甲公司委任處理該公司會計事務，因編製不實文件、憑證作假帳，犯了偽造文書罪，受有期 徒刑二年裁判確定（非緩刑），依記帳士法第 4 條規定，其記帳士證書被廢止，不得充任記帳士，但在', '["已執行完畢", "已執行完畢，再重新參 加記帳士考試及格", "一部之執行而赦免，再重新參加記帳士考試及格", "一部之執行而赦免已滿三年， 再重新參加記帳士考試及格 ⑤一部之執行而赦免已滿三年"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "c473f73014d0", "answer_pdf_sha1": "8e580acee728", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "602", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01038', 'bookkeeper', 'bookkeeper-moex-106-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '依現行記帳士法之規定，下列敘述何者錯誤？ 記帳士因業務之犯罪行為經移送法辦者，應付懲戒 記帳士應付懲戒者，由記帳士懲戒委員會處理之 記帳士受申誡處分3次以上者，應另受停止執行業務之處分 受停止執行業務處分累計滿五年者，應予除名', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "c473f73014d0", "answer_pdf_sha1": "8e580acee728", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "602", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 6, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01039', 'bookkeeper', 'bookkeeper-moex-106-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '依現行記帳士法之規定，下列敘述何者正確？ 記帳士接受委任代理各項業務，應與委任人訂立委任書 記帳士在登錄區域內，得受委任向財政部提起稅務案件訴願 記帳士接受客戶委任後，因故必須終止契約，應於15日前通知委任人 記帳士執行業務，依記帳士法規定應設置簿冊，其簿冊應保存10年', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "c473f73014d0", "answer_pdf_sha1": "8e580acee728", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "602", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 7, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01040', 'bookkeeper', 'bookkeeper-moex-106-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '逢稅公司106年12月31日帳上有分期付款銷貨之分期應收帳款餘額4,000,000元，未實現利息收入餘額 565,980元，有關該分期應收帳款，下列何者敘述錯誤？ 分期應收帳款餘額4,000,000元，可估列備抵呆帳 分期應收帳款屬流動資產 未實現利息收入，應列為分期應收帳款之減項 分期應收帳款餘額減除未實現利息收入餘額後淨額3,434,020元，可估列備抵呆帳', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "c473f73014d0", "answer_pdf_sha1": "8e580acee728", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "602", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 8, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
